class Solution {
    public List<Long> maximumEvenSplit(long finalSum) {
        List<Long> result = new ArrayList<>();
        if (finalSum % 2 != 0) {
            return result;
        }
        long S = finalSum;
        long k = 0;
        long low = 1;
        long high = S;

        // Binary search to find the maximum k where k*(k+1) <= S
        while (low <= high) {
            long mid = (low + high) / 2;
            long product = mid * (mid + 1);
            if (product <= S) {
                k = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }

        long R = S - k * (k + 1);
        if (R == 0) {
            for (int i = 1; i <= k; i++) {
                result.add(2L * i);
            }
        } else {
            if (R > 2 * k) {
                for (int i = 1; i <= k; i++) {
                    result.add(2L * i);
                }
                result.add(R);
            } else {
                for (int i = 1; i < k; i++) {
                    result.add(2L * i);
                }
                result.add(2L * k + R);
            }
        }
        return result;
    }
}

